313→    public function sessionMessages(Request $request): JsonResponse
314→    {
315→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
316→        if (!$this->inWhitelist($sfuserId)) {
317→            return $this->responseJsonFail('无权限');
318→        }
319→        $sessionId = $request->input('session_id');
320→
321→        // 校验会话归属
322→        $session = DB::table('daily_report_ai_sessions')
323→            ->where('id', $sessionId)
324→            ->where('sfuser_id', $sfuserId)
325→            ->whereNull('deleted_at')
326→            ->first();
327→
328→        if (!$session) {
329→            return $this->responseJsonSuccess(['list' => []]);
330→        }
331→
332→        $contextMaxChars = 5000;
333→        $messages = DB::table('daily_report_ai_messages')
334→            ->where('session_id', $sessionId)
335→            ->orderBy('id')
336→            ->get(['id', 'role', 'content', 'created_at']);
337→
338→        // context 消息截断，减少首次加载体积
339→        foreach ($messages as $msg) {
340→            if ($msg->role === 'context') {
341→                $fullLength = mb_strlen($msg->content);
342→                if ($fullLength > $contextMaxChars) {
343→                    $msg->content = mb_substr($msg->content, 0, $contextMaxChars);
344→                    $msg->is_truncated = true;
345→                    $msg->full_length = $fullLength;
346→                }
347→            }
348→        }
349→
350→        return $this->responseJsonSuccess(['list' => $messages]);
351→    }
