353→    /**
354→     * 加载更多 context 内容（分段返回）.
355→     */
356→    public function contextMore(Request $request): JsonResponse
357→    {
358→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
359→        if (!$this->inWhitelist($sfuserId)) {
360→            return $this->responseJsonFail('无权限');
361→        }
362→        $messageId = $request->input('message_id');
363→        $offset = (int)$request->input('offset', 0);
364→        $limit = 5000;
365→
366→        // 校验消息归属：message → session → sfuser
367→        $msg = DB::table('daily_report_ai_messages as m')
368→            ->join('daily_report_ai_sessions as s', 's.id', '=', 'm.session_id')
369→            ->where('m.id', $messageId)
370→            ->where('m.role', 'context')
371→            ->where('s.sfuser_id', $sfuserId)
372→            ->whereNull('s.deleted_at')
373→            ->select('m.content')
374→            ->first();
375→
376→        if (!$msg) {
377→            return $this->responseJsonFail('消息不存在');
378→        }
379→
380→        $fullLength = mb_strlen($msg->content);
381→        $chunk = mb_substr($msg->content, $offset, $limit);
382→        $hasMore = ($offset + $limit) < $fullLength;
383→
384→        return $this->responseJsonSuccess([
385→            'content' => $chunk,
386→            'offset' => $offset,
387→            'has_more' => $hasMore,
388→            'full_length' => $fullLength,
389→        ]);
390→    }
