675→    private function inWhitelist(int $sfuserId): bool
676→    {
677→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
678→        $result = $setting && $setting->is_on && in_array($sfuserId, $setting->ids ?? []);
679→        if (!$result) {
