681→                'sfuser_id' => $sfuserId,
682→                'has_setting' => !empty($setting),
683→                'is_on' => $setting->is_on ?? null,
684→                'ids' => $setting->ids ?? null,
685→            ]);
686→        }
687→        return $result;
688→    }
689→}
