 16→    public $queue = 'default';
 17→
 18→    /** 手动触发时传入具体 task ID，跳过时间/周期匹配（必须 public，private 属性队列序列化后丢失） */
 19→    public ?int $taskId;
 20→
 21→    /** 只发送指定的 group key（如 ['dept_6', 'dept_1']），为空则发送全部分组 */
 22→    public array $onlyGroupKeys;
 23→
 24→    public function __construct(?int $taskId = null, array $onlyGroupKeys = [])
 25→    {
 26→        $this->taskId = $taskId;
 27→        $this->onlyGroupKeys = $onlyGroupKeys;
 28→    }
 29→
 30→    public function handle(): bool
 31→    {
 32→        // 手动触发：直接处理指定任务，不检查时间和周期
 33→        if ($this->taskId) {
 34→            $task = DB::table('daily_report_ai_email_tasks')
 35→                ->whereNull('deleted_at')
 36→                ->where('id', $this->taskId)
 37→                ->first();
 38→
 39→            if (!$task) {
 40→                info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} not found");
 41→                return true;
 42→            }
 43→
 44→            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId}");
 45→            $this->processTask($task);
 46→            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} done");
 47→            return true;
 48→        }
 49→
 50→        // 定时调度：按时间和周期匹配任务
 51→        $now = now();
 52→        $currentTime = $now->format('H:i');
 53→        $currentDayOfWeek = $now->dayOfWeekIso; // 1=Monday, 7=Sunday
 54→        $currentDayOfMonth = $now->day;
 55→
 56→        info("[lbl][0416-AI日报][AiEmailJob] handle started, currentTime={$currentTime}, dayOfWeek={$currentDayOfWeek}, dayOfMonth={$currentDayOfMonth}");
 57→
 58→        $tasks = DB::table('daily_report_ai_email_tasks')
 59→            ->where('is_on', 1)
 60→            ->whereNull('deleted_at')
 61→            ->where('send_time', $currentTime)
 62→            ->get();
 63→
 64→        if ($tasks->isEmpty()) {
 65→            info("[lbl][0416-AI日报][AiEmailJob] no matching tasks for time={$currentTime}, skip");
 66→            return true;
 67→        }
 68→
 69→        info("[lbl][0416-AI日报][AiEmailJob] found {$tasks->count()} task(s) for time={$currentTime}");
 70→
 71→        foreach ($tasks as $task) {
 72→            if (!$this->shouldSendNow($task, $currentDayOfWeek, $currentDayOfMonth)) {
 73→                continue;
 74→            }
 75→
 76→            try {
 77→                $this->processTask($task);
 78→            } catch (\Throwable $e) {
 79→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} failed: {$e->getMessage()}".$e->getTraceAsString());
 80→            }
 81→        }
 82→
 83→        info('[lbl][0416-AI日报][AiEmailJob] finished');
 84→        return true;
 85→    }
 86→
 87→    private function shouldSendNow(object $task, int $dayOfWeek, int $dayOfMonth): bool
 88→    {
 89→        $sendDay = (int)($task->send_day ?? 1);
 90→
 91→        return match ($task->send_cycle) {
 92→            'daily' => true,
 93→            'weekly' => $dayOfWeek === $sendDay,
 94→            'monthly' => $this->isMonthlyMatch($sendDay, $dayOfMonth),
 95→            default => false,
 96→        };
 97→    }
 98→
 99→    /**
100→     * 月度匹配：如果设定日超过当月天数，则在当月最后一天触发.
101→     */
102→    private function isMonthlyMatch(int $sendDay, int $dayOfMonth): bool
103→    {
104→        $lastDayOfMonth = (int)now()->endOfMonth()->day;
105→        $effectiveDay = min($sendDay, $lastDayOfMonth);
106→
107→        return $dayOfMonth === $effectiveDay;
108→    }
109→
110→    private function processTask(object $task): void
111→    {
112→        $taskStartTime = microtime(true);
113→        $sfuserId = $task->sfuser_id;
114→
115→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} processTask start", [
116→            'sfuser_id' => $sfuserId,
117→            'dimension' => $task->dimension,
118→            'report_range' => $task->report_range,
119→            'send_cycle' => $task->send_cycle,
120→            'prompt_len' => mb_strlen($task->system_prompt ?? ''),
121→        ]);
122→
123→        // 读取邮箱配置
124→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
125→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
126→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no email config, skip");
127→            return;
128→        }
129→
130→        $toEmails = Arr::get($mc->config, 'to_email');
131→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
132→        if (!$sfuserToken) {
133→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no sfuser_token, skip");
134→            return;
135→        }
136→
137→        // 确定日报日期范围
138→        [$startDate, $endDate] = $this->getDateRange($task->report_range);
139→
140→        // 拉取该用户能看到日报的全部员工（维度只决定分组方式）
141→        $t0 = microtime(true);
142→        $dailyService = app(DailyReportService::class);
143→        $subordinates = $dailyService->getSubordinates($sfuserId);
144→        // group_users 是二维数组 [groupId => [userId, ...]]，需要 flatten
145→        $groupUserIds = [];
146→        foreach ($subordinates['group_users'] as $userIds) {
147→            $groupUserIds = array_merge($groupUserIds, $userIds);
148→        }
149→        $targetUserIds = array_unique(array_merge(
150→            $subordinates['direct_subordinates'],
151→            $subordinates['depart_subordinates'],
152→            $subordinates['other_subordinates'],
153→            $subordinates['focus_users'],
154→            $groupUserIds
155→        ));
156→
157→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} getSubordinates done", [
158→            'elapsed' => round(microtime(true) - $t0, 2),
159→            'target_user_count' => count($targetUserIds),
160→            'direct' => count($subordinates['direct_subordinates']),
161→            'depart' => count($subordinates['depart_subordinates']),
162→            'other' => count($subordinates['other_subordinates']),
163→            'focus' => count($subordinates['focus_users']),
164→            'group' => count($groupUserIds),
165→        ]);
166→
167→        if (empty($targetUserIds)) {
168→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no visible users, skip");
169→            return;
170→        }
171→
172→        // 拉取日报数据
173→        $t0 = microtime(true);
174→        $data = $dailyService->getOthersDailyReportListEnable(
175→            $startDate,
176→            $endDate,
177→            $sfuserId,
178→            $targetUserIds,
179→            10000
180→        );
181→        $reportCount = count($data['reports']['report_list'] ?? []);
182→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} getReports done", [
183→            'elapsed' => round(microtime(true) - $t0, 2),
184→            'date_range' => "{$startDate}~{$endDate}",
185→            'report_count' => $reportCount,
186→        ]);
187→
188→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
189→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no report data, skip");
190→            return;
191→        }
192→
193→        $reportList = $data['reports']['report_list'];
194→
195→        // 收集所有日报涉及的 sfuser_id
196→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
197→
198→        // 查询分组信息：按部门需要 department_id + department_name，按直接主管需要 direct_supervisor_id + direct_supervisor_nickname
199→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $task->dimension);
200→
201→        // 按维度分组日报
202→        $grouped = [];
203→        foreach ($reportList as $report) {
204→            $uid = $report['sfuser_id'];
205→            $groupKey = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
206→            $grouped[$groupKey]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
207→            $grouped[$groupKey]['reports'][] = $report;
208→        }
209→
210→        $groupSummary = array_map(fn ($g) => ($g['name'] ?? '?').'('.count($g['reports']).'人)', $grouped);
211→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} grouped", [
212→            'dimension' => $task->dimension,
213→            'group_count' => count($grouped),
214→            'groups' => $groupSummary,
215→            'to_emails' => $toEmails,
216→        ]);
217→
218→        // 按 onlyGroupKeys 过滤分组
219→        if (!empty($this->onlyGroupKeys)) {
220→            $grouped = array_intersect_key($grouped, array_flip($this->onlyGroupKeys));
221→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} filtered to groups: ".implode(',', $this->onlyGroupKeys).', matched='.count($grouped));
222→        }
223→
224→        // 每个分组独立发送一封邮件，各自独立 AI 分析
225→        $groupIndex = 0;
226→        $totalGroups = count($grouped);
227→        foreach ($grouped as $groupKey => $group) {
228→            ++$groupIndex;
229→            try {
230→                $groupName = $group['name'];
231→                $reports = $group['reports'];
232→
233→                $dimensionLabel = $task->dimension === 'direct_manager' ? '直属主管' : '部门';
234→                $groupNameMarked = EncryptService::app()->markEncrString($groupName);
235→                // 在日报内容前加上分组上下文，解密后 AI 能识别
236→                $content = "<p><b>{$dimensionLabel}：{$groupNameMarked}</b></p>\n";
237→                $no = 0;
238→                foreach ($reports as $report) {
239→                    $nickname = $report['data']['nickname'] ?? '';
240→                    if (empty($nickname)) {
241→                        continue;
242→                    }
243→                    $nickname = EncryptService::app()->markEncrString(e($nickname));
244→                    $reportContent = EncryptService::app()->markEncrString($report['content']);
245→                    ++$no;
246→                    $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
247→                    $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
248→                }
249→
250→                if ($no === 0) {
251→                    info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} group={$groupName} no valid reports, skip");
252→                    continue;
253→                }
254→
255→                $subject = "【{$startDate}】 {$task->name}（{$dimensionLabel}：{$groupNameMarked}）- 智能日报";
256→
257→                $params = [
258→                    'decrypt_config' => [
259→                        'obj' => '$this',
260→                        'decrypt_columns' => [],
261→                        'partly_decrypt_columns' => ['content', 'subject'],
262→                    ],
263→                    'receivers' => [[
264→                        'type' => 'token',
265→                        'tokens' => [$sfuserToken],
266→                        'filter' => 'emails',
267→                        'filter_map' => ['emails' => $toEmails],
268→                    ]],
269→                    'content' => $content,
270→                    'subject' => $subject,
271→                    'ai_analysis_config' => [
272→                        'system_prompt' => $task->system_prompt,
273→                        'compress' => true,
274→                    ],
275→                ];
276→
277→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] sending", [
278→                    'group_key' => $groupKey,
279→                    'group_name' => $groupName,
280→                    'report_count' => $no,
281→                    'content_bytes' => strlen($content),
282→                    'content_chars' => mb_strlen($content),
283→                    'subject' => $subject,
284→                ]);
285→
286→                $t0 = microtime(true);
287→                $result = CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
288→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] CoreApi responded", [
289→                    'group_name' => $groupName,
290→                    'elapsed' => round(microtime(true) - $t0, 2),
291→                    'result_code' => $result['error_code'] ?? null,
292→                    'result_msg' => $result['error_msg'] ?? null,
293→                ]);
294→            } catch (\Throwable $e) {
295→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] group={$group['name']} failed", [
296→                    'error' => $e->getMessage(),
297→                    'trace' => mb_substr($e->getTraceAsString(), 0, 500),
298→                ]);
299→            }
300→
301→            // 分组间隔 65 秒，避免短时间内多个大请求打满 Vertex AI TPM 配额
302→            if ($groupIndex < $totalGroups) {
303→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} sleeping 65s before next group");
304→                sleep(65);
305→            }
306→        }
307→
308→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} all groups sent", [
309→            'total_groups' => $totalGroups,
310→            'total_elapsed' => round(microtime(true) - $taskStartTime, 2),
311→        ]);
312→    }
313→
314→    /**
315→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
316→     */
317→    private function buildGroupMap(array $sfuserIds, string $dimension): array
318→    {
319→        if (empty($sfuserIds)) {
320→            return [];
321→        }
322→
323→        $map = [];
324→
325→        if ($dimension === 'direct_manager') {
326→            // 按直接主管分组
327→            $users = Sfuser::whereIn('id', $sfuserIds)
328→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
329→                ->get();
330→
331→            foreach ($users as $user) {
332→                $managerId = $user->direct_supervisor_id ?: 0;
333→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
334→                $map[$user->id] = [
335→                    'key' => "mgr_{$managerId}",
336→                    'name' => $managerName,
337→                ];
338→            }
339→        } else {
340→            // 按部门分组
341→            $users = Sfuser::whereIn('id', $sfuserIds)
342→                ->select('id', 'department_id')
343→                ->get();
344→
345→            // 批量查部门名称
346→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
347→            $deptNames = [];
348→            if (!empty($deptIds)) {
349→                $deptNames = DB::table('job_departments')
350→                    ->whereIn('department_id', $deptIds)
351→                    ->pluck('department_name', 'department_id')
352→                    ->toArray();
353→            }
354→
355→            foreach ($users as $user) {
356→                $deptId = $user->department_id ?: 0;
357→                $deptName = $deptNames[$deptId] ?? '未分配部门';
358→                $map[$user->id] = [
359→                    'key' => "dept_{$deptId}",
360→                    'name' => $deptName,
361→                ];
362→            }
363→        }
364→
365→        return $map;
366→    }
367→
368→    private function getDateRange(string $reportRange): array
369→    {
370→        $today = now()->toDateString();
371→        return match ($reportRange) {
372→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
373→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
374→            default => [$today, $today],
375→        };
376→    }
377→}
