  3→namespace App\Services;
  4→
  5→use Illuminate\Support\Arr;
  6→use Illuminate\Support\Facades\Log;
  7→
  8→class AiAnalysisService
  9→{
 10→    use ServiceTrait;
 11→
 12→    /**
 13→     * Blocking 模式：调用 AI，返回完整分析结果。
 14→     */
 15→    public function analyze(string $content, string $systemPrompt): string
 16→    {
 17→        Log::info('[lbl][0416-AI日报][AiAnalysis][CALL] blocking request', [
 18→            'content_len' => mb_strlen($content),
 19→            'content_preview' => mb_substr($content, 0, 100),
 20→            'prompt_len' => mb_strlen($systemPrompt),
 21→            'prompt_preview' => mb_substr($systemPrompt, 0, 100),
 22→            'vertex_project' => config('vertex_ai.project_id'),
 23→            'vertex_model' => config('vertex_ai.model'),
 24→        ]);
 25→
 26→        return $this->analyzeVertexAi($content, $systemPrompt);
 27→    }
 28→
 29→    /**
 30→     * Streaming 模式：调用 AI，通过回调逐 chunk 输出。
 31→     */
 32→    public function analyzeStream(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
 33→    {
 34→        Log::info('[lbl][0416-AI日报][AiAnalysis][CALL] streaming request', [
 35→            'content_len' => mb_strlen($content),
 36→            'content_preview' => mb_substr($content, 0, 100),
 37→            'prompt_len' => mb_strlen($systemPrompt),
 38→            'prompt_preview' => mb_substr($systemPrompt, 0, 100),
 39→            'history_count' => count($history),
 40→            'vertex_project' => config('vertex_ai.project_id'),
 41→            'vertex_model' => config('vertex_ai.model'),
 42→        ]);
 43→
 44→        return $this->analyzeStreamVertexAi($content, $systemPrompt, $onChunk, $history);
 45→    }
 46→
 47→    // ----------------------------------------------------------------
 48→    // Vertex AI 接口
 49→    // ----------------------------------------------------------------
 50→
 51→    /**
 52→     * Vertex AI Blocking 模式（OpenAI 兼容格式）。
 53→     */
 54→    private function analyzeVertexAi(string $content, string $systemPrompt): string
 55→    {
 56→        [$endpoint, $model] = $this->getVertexAiEndpoint();
 57→
 58→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI][CALL] blocking 请求 Vertex AI', [
 59→            'url' => $endpoint,
 60→            'model' => $model,
 61→            'content_len' => mb_strlen($content),
 62→            'prompt_len' => mb_strlen($systemPrompt),
 63→        ]);
 64→
 65→        $payload = json_encode([
 66→            'model' => $model,
 67→            'messages' => [
 68→                ['role' => 'system', 'content' => $systemPrompt],
 69→                ['role' => 'user', 'content' => $content],
 70→            ],
 71→            'stream' => false,
 72→        ], JSON_UNESCAPED_UNICODE);
 73→
 74→        $maxRetries = 4;
 75→        $baseDelay = 2; // 指数退避基准（秒），实际延迟 = baseDelay * 2^attempt + jitter
 76→
 77→        for ($attempt = 1; $attempt <= $maxRetries; ++$attempt) {
 78→            $accessToken = $this->getAccessToken();
 79→            if (empty($accessToken)) {
 80→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] failed to get access token', ['attempt' => $attempt]);
 81→                if ($attempt < $maxRetries) {
 82→                    $this->retrySleep($baseDelay, $attempt);
 83→                }
 84→                continue;
 85→            }
 86→
 87→            $startTime = microtime(true);
 88→            $ch = curl_init($endpoint);
 89→            curl_setopt_array($ch, [
 90→                CURLOPT_POST => true,
 91→                CURLOPT_POSTFIELDS => $payload,
 92→                CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$accessToken, 'Expect: '],
 93→                CURLOPT_USERAGENT => 'GCP-PHP-Client/1.0',
 94→                CURLOPT_RETURNTRANSFER => true,
 95→                CURLOPT_TIMEOUT => 120,
 96→                CURLOPT_CONNECTTIMEOUT => 10,
 97→            ]);
 98→
 99→            $response = curl_exec($ch);
100→            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
101→            $curlErrNo = curl_errno($ch);
102→            $curlError = $response === false ? curl_error($ch) : '';
103→            $elapsed = round(microtime(true) - $startTime, 2);
104→            curl_close($ch);
105→
106→            // curl 网络/超时错误 → 可重试
107→            if ($curlError) {
108→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] curl error, attempt {attempt}/{max}', [
109→                    'attempt' => $attempt, 'max' => $maxRetries,
110→                    'error' => $curlError, 'curl_errno' => $curlErrNo, 'elapsed' => $elapsed,
111→                ]);
112→                if ($attempt < $maxRetries) {
113→                    $this->retrySleep($baseDelay, $attempt);
114→                }
115→                continue;
116→            }
117→
118→            // 5xx 服务端错误 → 可重试
119→            if ($httpCode >= 500) {
120→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] server error, attempt {attempt}/{max}', [
121→                    'attempt' => $attempt, 'max' => $maxRetries,
122→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
123→                    'raw' => mb_substr($response, 0, 500),
124→                ]);
125→                if ($attempt < $maxRetries) {
126→                    $this->retrySleep($baseDelay, $attempt);
127→                }
128→                continue;
129→            }
130→
131→            // 429 限流 → 可重试
132→            if ($httpCode === 429) {
133→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] rate limited (429), attempt {attempt}/{max}', [
134→                    'attempt' => $attempt, 'max' => $maxRetries,
135→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
136→                    'raw' => mb_substr($response, 0, 500),
137→                ]);
138→                if ($attempt < $maxRetries) {
139→                    $this->retrySleep($baseDelay, $attempt);
140→                }
141→                continue;
142→            }
143→
144→            // 其他 4xx 客户端错误 → 不重试
145→            if ($httpCode >= 400) {
146→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] client error, not retrying', [
147→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
148→                    'raw' => mb_substr($response, 0, 1000),
149→                ]);
150→                return '';
151→            }
152→
153→            $result = json_decode($response, true);
154→            if (!is_array($result)) {
155→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] invalid response', [
156→                    'http_code' => $httpCode, 'elapsed' => $elapsed,
157→                    'raw' => mb_substr($response, 0, 1000),
158→                ]);
159→                return '';
160→            }
161→
162→            $answer = Arr::get($result, 'choices.0.message.content', '');
163→            Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] blocking done', [
164→                'http_code' => $httpCode, 'answer_len' => mb_strlen($answer),
165→                'elapsed' => $elapsed, 'attempt' => $attempt,
166→            ]);
167→
168→            return $answer;
169→        }
170→
171→        Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] all {max} attempts failed', ['max' => $maxRetries]);
172→        return '';
173→    }
174→
175→    /**
176→     * Vertex AI Streaming 模式（OpenAI 兼容格式）。
177→     */
178→    private function analyzeStreamVertexAi(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
179→    {
180→        [$endpoint, $model] = $this->getVertexAiEndpoint();
181→
182→        $messages = [['role' => 'system', 'content' => $systemPrompt]];
183→        foreach ($history as $msg) {
184→            $messages[] = ['role' => $msg['role'], 'content' => $msg['content']];
185→        }
186→        if (!empty($content)) {
187→            $messages[] = ['role' => 'user', 'content' => $content];
188→        }
189→
190→        $payload = json_encode([
191→            'model' => $model,
192→            'messages' => $messages,
193→            'stream' => true,
194→        ], JSON_UNESCAPED_UNICODE);
195→
196→        $maxRetries = 4;
197→        $baseDelay = 2; // 指数退避基准（秒），实际延迟 = baseDelay * 2^attempt + jitter
198→
199→        for ($attempt = 1; $attempt <= $maxRetries; ++$attempt) {
200→            $accessToken = $this->getAccessToken();
201→            if (empty($accessToken)) {
202→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] failed to get access token', ['attempt' => $attempt]);
203→                if ($attempt < $maxRetries) {
204→                    $this->retrySleep($baseDelay, $attempt);
205→                }
206→                continue;
207→            }
208→
209→            Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI][CALL] streaming 请求 Vertex AI', [
210→                'url' => $endpoint,
211→                'model' => $model,
212→                'content_len' => mb_strlen($content),
213→                'prompt_len' => mb_strlen($systemPrompt),
214→                'history_count' => count($history),
215→                'attempt' => $attempt,
216→            ]);
217→
218→            $fullReply = '';
219→            $buffer = '';
220→            $rawResponse = '';
221→
222→            $ch = curl_init($endpoint);
223→            curl_setopt_array($ch, [
224→                CURLOPT_POST => true,
225→                CURLOPT_POSTFIELDS => $payload,
226→                CURLOPT_HTTPHEADER => ['Content-Type: application/json', 'Authorization: Bearer '.$accessToken, 'Expect: '],
227→                CURLOPT_USERAGENT => 'GCP-PHP-Client/1.0',
228→                CURLOPT_RETURNTRANSFER => false,
229→                CURLOPT_TIMEOUT => 300,
230→                CURLOPT_CONNECTTIMEOUT => 10,
231→                CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, &$rawResponse, $onChunk) {
232→                    $rawResponse .= $data;
233→                    $buffer .= $data;
234→
235→                    while (($pos = strpos($buffer, "\n")) !== false) {
236→                        $line = rtrim(substr($buffer, 0, $pos), "\r");
237→                        $buffer = substr($buffer, $pos + 1);
238→
239→                        if (!str_starts_with($line, 'data: ')) {
240→                            continue;
241→                        }
242→
243→                        $jsonStr = substr($line, 6);
244→                        if ($jsonStr === '[DONE]') {
245→                            continue;
246→                        }
247→
248→                        $decoded = json_decode($jsonStr, true);
249→                        if (!is_array($decoded)) {
250→                            continue;
251→                        }
252→
253→                        $chunk = Arr::get($decoded, 'choices.0.delta.content', '');
254→                        if ($chunk !== '') {
255→                            $fullReply .= $chunk;
256→                            $onChunk($chunk);
257→                        }
258→                    }
259→
260→                    return strlen($data);
261→                },
262→            ]);
263→
264→            curl_exec($ch);
265→            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
266→            $curlErrNo = curl_errno($ch);
267→            $curlError = curl_error($ch);
268→            curl_close($ch);
269→
270→            // curl 网络/超时错误 → 可重试
271→            if ($curlError) {
272→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming curl error, attempt {attempt}/{max}', [
273→                    'attempt' => $attempt, 'max' => $maxRetries,
274→                    'error' => $curlError, 'curl_errno' => $curlErrNo,
275→                ]);
276→                if ($attempt < $maxRetries) {
277→                    $this->retrySleep($baseDelay, $attempt);
278→                }
279→                continue;
280→            }
281→
282→            // 429 限流 或 5xx 服务端错误 → 可重试
283→            if ($httpCode === 429 || $httpCode >= 500) {
284→                Log::warning('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming retryable error, attempt {attempt}/{max}', [
285→                    'attempt' => $attempt, 'max' => $maxRetries,
286→                    'http_code' => $httpCode,
287→                    'raw' => mb_substr($rawResponse, 0, 500),
288→                ]);
289→                if ($attempt < $maxRetries) {
290→                    $this->retrySleep($baseDelay, $attempt);
291→                }
292→                continue;
293→            }
294→
295→            // 其他 4xx → 不重试
296→            if ($httpCode >= 400) {
297→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming client error, not retrying', [
298→                    'http_code' => $httpCode,
299→                    'raw' => mb_substr($rawResponse, 0, 1000),
300→                ]);
301→                return '';
302→            }
303→
304→            // 空回复检查
305→            if (empty($fullReply) && !empty($rawResponse)) {
306→                Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming empty reply', [
307→                    'http_code' => $httpCode,
308→                    'raw' => mb_substr($rawResponse, 0, 1000),
309→                ]);
310→                $jsonErr = json_decode($rawResponse, true);
311→                if (is_array($jsonErr) && isset($jsonErr['error'])) {
312→                    Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] api error in stream', [
313→                        'error' => $jsonErr['error'],
314→                    ]);
315→                }
316→                // 空回复但 HTTP 200，可能是解析问题，不重试
317→                return '';
318→            }
319→
320→            Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming done', [
321→                'http_code' => $httpCode,
322→                'reply_len' => mb_strlen($fullReply),
323→                'attempt' => $attempt,
324→            ]);
325→
326→            return $fullReply;
327→        }
328→
329→        Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming all {max} attempts failed', ['max' => $maxRetries]);
330→        return '';
331→    }
332→
333→    /**
334→     * 指数退避 + 随机 jitter，上限 60 秒。
335→     * delay = min(baseDelay * 2^attempt + jitter, 60).
336→     */
337→    private function retrySleep(int $baseDelay, int $attempt): void
338→    {
339→        $delay = min($baseDelay * (2 ** $attempt) + random_int(0, 3), 60);
340→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] retry sleep', ['delay' => $delay, 'attempt' => $attempt]);
341→        sleep($delay);
342→    }
