344→    /**
345→     * 构建 Vertex AI 的 endpoint URL 和 model。
346→     */
347→    private function getVertexAiEndpoint(): array
348→    {
349→        $projectId = config('vertex_ai.project_id');
350→        $location = config('vertex_ai.location', 'us-central1');
351→        $model = config('vertex_ai.model', 'google/gemini-2.5-flash');
352→        // global 端点无 location 前缀（Gemini 3.x Preview 仅支持 global）
353→        $host = $location === 'global'
354→            ? 'aiplatform.googleapis.com'
355→            : "{$location}-aiplatform.googleapis.com";
356→        $endpoint = "https://{$host}/v1/projects/{$projectId}/locations/{$location}/endpoints/openapi/chat/completions";
357→
358→        return [$endpoint, $model];
359→    }
