361→    /**
362→     * 通过 GCE Metadata Server 获取 Service Account 的 access token。
363→     */
364→    private function getAccessToken(): string
365→    {
366→        $url = 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token';
367→        $context = stream_context_create([
368→            'http' => [
369→                'header' => 'Metadata-Flavor: Google',
370→                'timeout' => 5,
371→            ],
372→        ]);
373→
374→        $response = @file_get_contents($url, false, $context);
375→        if ($response === false) {
376→            Log::error('[lbl][0416-AI日报][AiAnalysis] failed to get access token from metadata server');
377→            return '';
378→        }
379→
380→        $data = json_decode($response, true);
381→        return $data['access_token'] ?? '';
382→    }
383→}
