 35→    public function transfer(Request $request, string $action = ''): mixed
 36→    {
 37→        $params = $request->all();
 38→
 39→        // 提取特定的请求参数
 40→        $reservedWords = [
 41→            'decrypt_config', 'encrypt_config', 'update_permission', 'next_replace_filter',
 42→            'hash_filter', 'replace_filter', 'authorize_config', 'intact_columns', 'response_format',
 43→            'ai_analysis_config',
 44→        ];
 45→        foreach ($reservedWords as $word) {
 46→            ${$word} = $params[$word] ?? null;
 47→            unset($params[$word]);
 48→        }
 49→
 50→        // 对请求参数进行加密
 51→        if (!empty($encrypt_config)) {
 52→            if (Arr::isAssoc($encrypt_config)) {
 53→                $encrypt_config = [$encrypt_config];
 54→            }
 55→            foreach ($encrypt_config as $conf) {
 56→                $params = EncryptService::app()->encryptData($params, $conf);
 57→            }
 58→        } else {
 59→            // 分页、版本号、语言控制参数应当默认放行
 60→            $intact_columns = array_merge_index($intact_columns ?? [], ['version_info', 'sys_lang', 'page', 'per_page']);
 61→            // 对所有 intact_columns 之外的属性进行 unset，该字段无需递归处理
 62→            $intact_columns = Arr::wrap($intact_columns);
 63→            $params = Arr::only($params, $intact_columns);
 64→        }
 65→
 66→        // 处理请求参数中“更新权限”的操作
 67→        if (!empty($update_permission)) {
 68→            if (Arr::isAssoc($update_permission)) {
 69→                $update_permission = [$update_permission];
 70→            }
 71→            foreach ($update_permission as $conf) {
 72→                $params = ResourceService::app()->updateResPermission($params, $conf);
 73→            }
 74→        }
 75→
 76→        // 处理请求参数中“哈希筛选”的参数
 77→        if (!empty($hash_filter)) {
 78→            $params = HashFilterService::app()->hashFilter($params, $hash_filter);
 79→        }
 80→
 81→        // 处理请求参数中“替换筛选”的参数
 82→        if (!empty($replace_filter)) {
 83→            $params = ReplaceFilterService::app()->replaceFilter($params, $replace_filter);
 84→        }
 85→
 86→        if (!empty($next_replace_filter)) {
 87→            $params = NextReplaceFilterService::app()->replaceFilter($params, $next_replace_filter);
 88→        }
 89→
 90→        // 处理请求参数中“授权”参数
 91→        if (!empty($authorize_config)) {
 92→            $token = AuthorizeService::app()->generateToken($authorize_config);
 93→            $params['authorized_token'] = $token;
 94→        }
 95→
 96→        // 有些接口是 stream response，这部分请求没办法用通用的 JSON 方式处理，所以这里直接转发，为了避免造成破坏性变更
 97→        // 这里只对部分接口进行特殊处理
 98→        if (!empty($response_format) && $response_format == 'stream') {
