107→                    if (isset($respData['decrypt_config'])) {
108→                        unset($respData['decrypt_config']);
109→                    }
110→                    if (!empty($decrypt_config)) {
111→                        // AI 场景容忍部分解密失败（throwEcp(false)），避免单个字段权限不足导致整体中断
112→                        $respData = DecryptService::app()->throwEcp(false)->decryptData($respData, $decrypt_config, $decrypt_config['operation'] ?? 'response');
113→                    }
114→
115→                    // 合并响应中的 ai_analysis_config（oa-server 可在响应中提供/覆盖 AI 配置）
116→                    if (!empty($respData['ai_analysis_config'])) {
117→                        $ai_analysis_config = array_merge($ai_analysis_config, $respData['ai_analysis_config']);
118→                        unset($respData['ai_analysis_config']);
119→                    }
120→
121→                    // 提取 AI 输入内容
122→                    $targetField = $ai_analysis_config['target_field'] ?? null;
123→                    $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
124→                    if (is_array($contentForAi)) {
