154→                            flush();
155→                        }
156→
157→                        AiAnalysisService::app()->analyzeStream(
158→                            $contentForAi,
159→                            $systemPrompt,
160→                            function (string $chunk) {
161→                                echo 'data: '.json_encode([
162→                                    'error_code' => 0,
163→                                    'error_msg' => '',
164→                                    'data' => ['type' => 'chat', 'is_finished' => false, 'content' => $chunk],
165→                                ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
166→                                ob_flush();
167→                                flush();
168→                            },
169→                            $history
