171→                        // 结束帧
172→                        echo 'data: '.json_encode([
173→                            'error_code' => 0,
174→                            'error_msg' => '',
175→                            'data' => ['type' => 'chat', 'is_finished' => true, 'content' => ''],
176→                        ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
177→                        ob_flush();
178→                        flush();
179→                    }, 200, [
180→                        'Content-Type' => 'text/event-stream',
181→                        'Cache-Control' => 'no-cache',
182→                        'X-Accel-Buffering' => 'no',
183→                    ]);
184→                }
185→
186→                // 后端返回错误（data 为空），以 SSE 格式返回错误信息给前端
187→                $errorMsg = $resp['error_msg'] ?? '后端服务返回错误';
188→                $errorCode = $resp['error_code'] ?? -1;
189→                Log::warning('[lbl][0416-AI日报][TransferRequest] AI stream: 后端返回错误, 以 SSE 返回', [
190→                    'error_code' => $errorCode,
191→                    'error_msg' => $errorMsg,
192→                ]);
193→                return response()->json([
194→                    'error_code' => $errorCode,
195→                    'error_msg' => $errorMsg,
196→                    'data' => null,
197→                ]);
198→            }
199→
200→            // 原有的 stream 透传逻辑不变
201→            $resp = $this->callBackendApi($action ?: $request->path(), $params, true);
202→            return response()->stream(function () use ($resp) {
203→                $body = $resp->toPsrResponse()->getBody();
204→                $content = '';
205→                while (!$body->eof()) {
