213→                    }
214→                }
215→            }, $resp->status(), array_merge($resp->headers(), ['X-Accel-Buffering' => 'no']));
216→        }
217→
218→        $resp = $this->callBackendApi($action ?: $request->path(), $params);
219→        if (!empty($resp['data'])) {
