 38→    /**
 39→     * 发送密文邮件，检查接收者的权限。
 40→     *
 41→     * @param \Illuminate\Http\Request $request
 42→     *
 43→     * @throws \App\Exceptions\UserException
 44→     * @throws \App\Exceptions\IOException
 45→     * @throws \App\Exceptions\ServerException
 46→     * @throws \App\Exceptions\CryptoException
 47→     * @throws \App\Exceptions\CommonException
 48→     * @return \Illuminate\Http\JsonResponse
 49→     */
 50→    public function sendDecr(Request $request): JsonResponse
 51→    {
 52→        Headers::$customLineLength = 512; // 调整 Header 长度
 53→        $params = $request->all();
 54→        $conf = $params['decrypt_config'];
 55→        unset($params['decrypt_config']);
 56→
 57→        $aiAnalysisConfig = $params['ai_analysis_config'] ?? null;
 58→        unset($params['ai_analysis_config']);
 59→
 60→        Log::info('[lbl][0416-AI日报][Mail][sendDecr] 收到请求', [
 61→            'has_ai_config' => !empty($aiAnalysisConfig),
 62→            'ai_prompt_len' => mb_strlen($aiAnalysisConfig['system_prompt'] ?? ''),
 63→            'ai_compress' => $aiAnalysisConfig['compress'] ?? false,
 64→            'subject_preview' => mb_substr($params['subject'] ?? '', 0, 100),
 65→            'content_len' => mb_strlen($params['content'] ?? ''),
 66→            'partly_decrypt' => $conf['partly_decrypt_columns'] ?? [],
 67→        ]);
 68→
 69→        // 通过 receivers 参数解析出接收者的邮箱
 70→        [$rcvEmails, $receivers] = AuthorizeService::app()->retrieveEmailsOfReceivers($params['receivers']);
 71→        unset($params['receivers']);
 72→
 73→        // 解密并检查收件人权限
 74→        // AI 分析场景：content 和 subject 都用 throwEcp(false)，权限不足的密文变成 [E:xxx] 形式，不阻断发送
 75→        // 普通场景：content 必须有权限（throwEcp），subject 允许部分解密失败
 76→        $subjectInPartly = in_array('subject', $conf['partly_decrypt_columns'] ?? [], true);
 77→        $contentInPartly = in_array('content', $conf['partly_decrypt_columns'] ?? [], true);
 78→        // 需要单独用 throwEcp(false) 解密的字段，先从 partly_decrypt_columns 中移除
 79→        $softDecryptFields = [];
 80→        if ($subjectInPartly) {
 81→            $softDecryptFields[] = 'subject';
 82→        }
 83→        if ($contentInPartly && !empty($aiAnalysisConfig)) {
 84→            $softDecryptFields[] = 'content';
 85→        }
 86→        if (!empty($softDecryptFields)) {
 87→            $conf['partly_decrypt_columns'] = array_values(array_diff($conf['partly_decrypt_columns'], $softDecryptFields));
 88→        }
 89→        $conf['receivers'] = $receivers;
 90→        $params = DecryptService::app()->throwEcp()->decryptData($params, $conf, 'send_email');
 91→
 92→        // 对需要宽容解密的字段，逐个用 throwEcp(false) 解密
 93→        foreach ($softDecryptFields as $field) {
 94→            $params[$field] = DecryptService::app()->throwEcp(false)->decryptText($params[$field]);
 95→        }
 96→        // 清理 subject 中权限不足的残留：[E:xxx]密文 → 去掉整个（维度：分组名）部分
 97→        if ($subjectInPartly) {
 98→            $params['subject'] = preg_replace('/（[^）]*\[E:\d+\][^）]*）/', '', $params['subject']);
 99→        }
100→
101→        // 如果配置了 AI 分析，对邮件内容进行分析并将摘要插入邮件头部
102→        if (!empty($aiAnalysisConfig) && !empty($aiAnalysisConfig['system_prompt'])) {
103→            Log::info('[lbl][0416-AI日报][Mail][AI] 开始AI分析邮件内容', [
104→                'content_len' => mb_strlen($params['content']),
105→                'content_preview' => mb_substr($params['content'], 0, 100),
106→                'prompt_len' => mb_strlen($aiAnalysisConfig['system_prompt']),
107→                'prompt_preview' => mb_substr($aiAnalysisConfig['system_prompt'], 0, 100),
108→                'compress' => !empty($aiAnalysisConfig['compress']),
109→                'receivers' => $rcvEmails,
110→            ]);
111→            $aiContent = $params['content'];
112→            // compress=true 时去掉 HTML 标签、压缩空白，减少 AI token 消耗
113→            if (!empty($aiAnalysisConfig['compress'])) {
114→                $aiContent = strip_tags($aiContent);
115→                $aiContent = preg_replace('/\n{3,}/', "\n\n", $aiContent);
116→                $aiContent = preg_replace('/[ \t]+/', ' ', $aiContent);
117→                $aiContent = trim($aiContent);
118→            }
119→            $aiStartTime = microtime(true);
120→            $aiResult = AiAnalysisService::app()->analyze(
121→                $aiContent,
122→                $aiAnalysisConfig['system_prompt']
123→            );
124→            $aiElapsed = round(microtime(true) - $aiStartTime, 2);
125→            if (!empty($aiResult)) {
126→                Log::info('[lbl][0416-AI日报][Mail][AI] AI分析完成, 直接作为邮件内容', [
127→                    'result_len' => mb_strlen($aiResult), 'elapsed' => $aiElapsed,
128→                ]);
129→                $params['content'] = \Illuminate\Support\Str::markdown($aiResult);
130→            } else {
131→                Log::error('[lbl][0416-AI日报][Mail][AI] AI分析返回空(含重试), 跳过发送', [
132→                    'elapsed' => $aiElapsed,
133→                    'backend' => 'vertex_ai',
134→                    'to' => $rcvEmails,
135→                    'subject_preview' => mb_substr($params['subject'] ?? '', 0, 80),
136→                    'content_len' => mb_strlen($params['content']),
137→                ]);
138→
139→                return $this->responseJsonSuccess(['success' => false, 'reason' => 'ai_analysis_empty']);
140→            }
141→        }
142→
143→        $mail = new BlankMail($params['content']);
144→        $mail->subject($params['subject']);
145→        $mail->to($rcvEmails);
146→
147→        if (!empty($params['attachments'])) {
148→            // 处理附件，根据真实文件名找到文件的存储路径
149→            foreach ($params['attachments'] as $one) {
150→                $filePath = FileService::app()->getRealFile($one['path'], $one['disk']);
151→                $realName = $one['real_name'] ?? $one['path'];
152→                // 为了支持 QQ 邮箱中文附件名过长时的显示和下载乱码问题，注意上面重载了 Header 长度
153→                // 这样可以保证 header 里面的附件名不被分隔，相关 rfc：2184，2231，2047
154→                // @see https://github.com/jstedfast/MimeKit/blob/master/FAQ.md#q-why-do-attachments-with-unicode-or-long-filenames-appear-as-att0dat-in-outlook
155→                $mail->attach($filePath, [
156→                    'as' => '=?UTF-8?B?'.base64_encode($realName).'?=',
157→                ]);
158→            }
159→        }
